// n8n Code Node: Website Platform Detector
// Input: leads with website URLs
// Output: leads with diy_platform field set (or null if professionally built)
//
// This runs as an n8n Code node. For each lead with a website,
// it makes an HTTP request and fingerprints the platform.
// Only leads with detected DIY platforms continue to Pipeline B.

// Platform signatures â€” checked against HTML source + headers
const PLATFORM_SIGNATURES = {
  wix: {
    html: [/wix\.com/i, /_wix_browser_sess/i, /wixsite\.com/i, /wix-warmup-data/i],
    headers: [/X-Wix-/i],
    generator: [/Wix\.com/i],
  },
  squarespace: {
    html: [/squarespace\.com/i, /sqsp/i, /static\.squarespace/i, /squarespace-cdn/i],
    headers: [/X-ServedBy.*squarespace/i],
    generator: [/Squarespace/i],
  },
  weebly: {
    html: [/weebly\.com/i, /editmysite\.com/i],
    headers: [],
    generator: [/Weebly/i],
  },
  wordpress_com: {
    // wordpress.COM (hosted/free) â€” not self-hosted wordpress.ORG
    html: [/s[0-9]\.wp\.com/i, /wordpress\.com/i, /wp-content\/themes\/starter/i],
    headers: [],
    generator: [/WordPress\.com/i],
  },
  godaddy: {
    html: [/godaddy\.com/i, /img1\.wsimg\.com/i, /secureserver\.net/i],
    headers: [],
    generator: [/GoDaddy/i],
  },
  jimdo: {
    html: [/jimdo\.com/i, /jimdosite\.com/i],
    headers: [],
    generator: [/Jimdo/i],
  },
  shopify: {
    // Shopify sites used as business websites (not just e-commerce)
    html: [/cdn\.shopify\.com/i, /myshopify\.com/i],
    headers: [/X-ShopId/i],
    generator: [],
  },
};

async function detectPlatform(url) {
  // Ensure URL has protocol
  if (!url.startsWith('http')) {
    url = 'https://' + url;
  }

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 10000);

    const response = await fetch(url, {
      redirect: 'follow',
      signal: controller.signal,
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
      },
    });

    clearTimeout(timeout);

    const html = await response.text();
    const headersStr = JSON.stringify(Object.fromEntries(response.headers));

    // Extract meta generator tag
    const generatorMatch = html.match(
      /<meta[^>]*name=["']generator["'][^>]*content=["']([^"']+)["']/i
    );
    const generator = generatorMatch ? generatorMatch[1] : '';

    // Check each platform's signatures
    for (const [platform, sigs] of Object.entries(PLATFORM_SIGNATURES)) {
      const htmlMatch = sigs.html.some(regex => regex.test(html));
      const headerMatch = sigs.headers.some(regex => regex.test(headersStr));
      const genMatch = sigs.generator.some(regex => regex.test(generator));

      if (htmlMatch || headerMatch || genMatch) {
        return platform;
      }
    }

    return null; // Not a DIY platform â€” likely professionally built
  } catch (err) {
    // Site unreachable, SSL error, timeout â€” skip
    return null;
  }
}

// n8n Code node entry point
const results = [];

for (const item of $input.all()) {
  const lead = item.json;

  if (!lead.website) {
    // No website â€” skip (this shouldn't be in Pipeline B)
    continue;
  }

  const platform = await detectPlatform(lead.website);

  if (platform) {
    // DIY platform detected â€” include in Pipeline B
    results.push({
      json: {
        ...lead,
        diy_platform: platform,
      },
    });
  }
  // If platform is null, the site is professionally built â€” exclude from Pipeline B
}

return results;

// For each DIY site, call Google PageSpeed API
const results = [];
for (const item of $input.all()) {
  const lead = item.json;
  if (!lead.website) continue;

  try {
    const url = encodeURIComponent(lead.website.startsWith('http') ? lead.website : 'https://' + lead.website);
    const apiUrl = 'https://www.googleapis.com/pagespeedonline/v5/runPagespeed?url=' + url + '&strategy=mobile&category=performance&category=seo';

    const response = await fetch(apiUrl, {signal: AbortSignal.timeout(15000)});
    const data = await response.json();

    const lh = data.lighthouseResult || {};
    const cats = lh.categories || {};
    const audits = lh.audits || {};

    const seoIssues = [];
    if (!audits['meta-description']?.score) seoIssues.push('missing_meta_desc');
    if (!audits['document-title']?.score) seoIssues.push('missing_title');
    if (audits['viewport']?.score === 0) seoIssues.push('no_viewport');
    if (audits['is-crawlable']?.score === 0) seoIssues.push('not_crawlable');

    results.push({
      json: {
        ...lead,
        pagespeed_score: Math.round((cats.performance?.score || 0) * 100),
        pagespeed_mobile: Math.round((cats.performance?.score || 0) * 100),
        has_ssl: lead.website.startsWith('https'),
        has_meta_description: !seoIssues.includes('missing_meta_desc'),
        has_h1: true,
        mobile_friendly: (cats.performance?.score || 0) > 0.5,
        seo_issues: seoIssues,
        core_web_vitals: {
          lcp: audits['largest-contentful-paint']?.numericValue / 1000 || null,
          fid: audits['max-potential-fid']?.numericValue / 1000 || null,
          cls: audits['cumulative-layout-shift']?.numericValue || null,
        }
      }
    });
  } catch (err) {
    // PageSpeed failed — still include lead but without audit data
    results.push({
      json: { ...lead, pagespeed_score: null, pagespeed_mobile: null }
    });
  }
}
return results;

// n8n Code Node: Lead Scorer â€” Pipeline B (DIY Website)
// Input: array of leads with DIY website + audit data
// Output: leads with score (0-10) + score_breakdown
//
// Paste this into an n8n Code node. It processes all items.

const FREE_EMAIL_DOMAINS = [
  'gmail.com', 'hotmail.com', 'outlook.com', 'yahoo.com',
  'icloud.com', 'live.com', 'aol.com', 'mail.com',
  'hotmail.com.au', 'outlook.com.au', 'yahoo.com.au',
  'bigpond.com', 'bigpond.net.au', 'optusnet.com.au',
];

const HIGH_VALUE_TRADES = [
  'plumber', 'electrician', 'builder', 'roofer', 'concreter',
  'landscaper', 'pool', 'painter', 'fencer', 'carpenter',
  'pest control', 'cleaner', 'air conditioning', 'solar',
  'bore', 'drilling', 'excavation', 'demolition',
  'tiler', 'tiling', 'glazier', 'glass', 'garage door',
  'handyman', 'cabinet', 'kitchen', 'bathroom',
];

function scoreDiyWebsiteLead(lead) {
  let score = 0;
  const breakdown = {};

  // Signal 1: PageSpeed score (worse = more opportunity)
  if (lead.pagespeed_score !== null && lead.pagespeed_score !== undefined) {
    if (lead.pagespeed_score < 30) {
      score += 3;
      breakdown.pagespeed = `+3 (PageSpeed ${lead.pagespeed_score}/100 â€” terrible)`;
    } else if (lead.pagespeed_score < 50) {
      score += 2;
      breakdown.pagespeed = `+2 (PageSpeed ${lead.pagespeed_score}/100 â€” poor)`;
    } else if (lead.pagespeed_score < 70) {
      score += 1;
      breakdown.pagespeed = `+1 (PageSpeed ${lead.pagespeed_score}/100 â€” mediocre)`;
    }
  }

  // Signal 2: Not mobile-friendly (huge for tradies â€” customers search on phone)
  if (lead.mobile_friendly === false) {
    score += 2;
    breakdown.mobile = '+2 (not mobile-friendly â€” losing phone searchers)';
  }

  // Signal 3: No SSL (browser shows "Not Secure")
  if (lead.has_ssl === false) {
    score += 1;
    breakdown.ssl = '+1 (no SSL â€” browser shows "Not Secure" warning)';
  }

  // Signal 4: SEO issues
  const seoIssues = lead.seo_issues || [];
  if (seoIssues.length >= 3) {
    score += 2;
    breakdown.seo = `+2 (${seoIssues.length} SEO issues found)`;
  } else if (seoIssues.length >= 1) {
    score += 1;
    breakdown.seo = `+1 (${seoIssues.length} SEO issue(s) found)`;
  }

